+       // Reset original missing status
+ 
+-      vector<Individual*>::iterator i = PP->sample.begin();
+-      while ( i != PP->sample.end() )
++      vector<Individual*>::iterator ipp = PP->sample.begin();
++      while ( ipp != PP->sample.end() )
+ 	{
+-	  (*i)->missing = (*i)->flag;
+-	  ++i;
++	  (*ipp)->missing = (*ipp)->flag;
++	  ++ipp;
+ 	}
